const items = .all();
// 简单TF-IDF + 关键词统计
const wordCount = {};
items.forEach(item => {
  const text = (item.json.title + ' ' + item.json.content).toLowerCase();
  const words = text.match(/[一-龥]{2,5}/g) || [];
  words.forEach(w => { wordCount[w] = (wordCount[w] || 0) + 1; });
});
const sorted = Object.entries(wordCount).sort((a,b) => b[1]-a[1]).slice(0,10);
return sorted.map(([keyword, count]) => ({keyword, count}));
